scwin.gr_deposit_oncellclick = function (rowIndex, columnIndex, columnId) {
    console.log("columnId =>" + columnId);
    if ( columnId == "bankbookNo" ) {
        scwin.f_BankBookPopUpDeposit(rowIndex,columnId,"ALL");
    }
};
